// UpdateNewValues updates the mutable fields using the new values that
// were set on create. Using this option is equivalent to using:
//
//	client.SchemaChange.Create().
//		OnConflict(
//			sql.ResolveWithNewValues(),
//			sql.ResolveWith(func(u *sql.UpdateSet) {
//				u.SetIgnore(schemachange.FieldID)
//			}),
//		).
//		Exec(ctx)
func (u *SchemaChangeUpsertBulk) UpdateNewValues() *SchemaChangeUpsertBulk {
	u.create.conflict = append(u.create.conflict, sql.ResolveWithNewValues())
	u.create.conflict = append(u.create.conflict, sql.ResolveWith(func(s *sql.UpdateSet) {
		for _, b := range u.create.builders {
			if _, exists := b.mutation.ID(); exists {
				s.SetIgnore(schemachange.FieldID)
			}
			if _, exists := b.mutation.Asset(); exists {
				s.SetIgnore(schemachange.FieldAsset)
			}
			if _, exists := b.mutation.RunID(); exists {
				s.SetIgnore(schemachange.FieldRunID)
			}
			if _, exists := b.mutation.CodeHash(); exists {
				s.SetIgnore(schemachange.FieldCodeHash)
			}
			if _, exists := b.mutation.PrevVersionID(); exists {
				s.SetIgnore(schemachange.FieldPrevVersionID)
			}
			if _, exists := b.mutation.NewVersionID(); exists {
				s.SetIgnore(schemachange.FieldNewVersionID)
			}
			if _, exists := b.mutation.ChangeType(); exists {
				s.SetIgnore(schemachange.FieldChangeType)
			}
			if _, exists := b.mutation.ColumnName(); exists {
				s.SetIgnore(schemachange.FieldColumnName)
			}
			if _, exists := b.mutation.PrevType(); exists {
				s.SetIgnore(schemachange.FieldPrevType)
			}
			if _, exists := b.mutation.NewType(); exists {
				s.SetIgnore(schemachange.FieldNewType)
			}
			if _, exists := b.mutation.PrevNullable(); exists {
				s.SetIgnore(schemachange.FieldPrevNullable)
			}
			if _, exists := b.mutation.NewNullable(); exists {
				s.SetIgnore(schemachange.FieldNewNullable)
			}
			if _, exists := b.mutation.IsBreaking(); exists {
				s.SetIgnore(schemachange.FieldIsBreaking)
			}
			if _, exists := b.mutation.ObservedAt(); exists {
				s.SetIgnore(schemachange.FieldObservedAt)
			}
		}
	}))
	return u
}

